INSERT INTO jpms_education_concepts (id, name_ja, name_en, name_original, definition, impact_summary, subfield, school_of_thought, era_start, era_end, opposing_concept_names, keywords_ja, keywords_en, key_researchers, key_works, relevance_to_middle_school, status, source_reliability, data_completeness) VALUES
('jpms_ec_0009', '構成主義学習理論', 'Constructivism', 'Constructivism', '学習者が既有知識と新しい経験を相互作用させながら、能動的に知識を構成するという理論。Piaget の認知的構成主義（個人の思考スキーマの発達）と Vygotsky の社会的構成主義（社会文化的文脈での協働的知識構築）を区別する。学習を受動的な受信ではなく、実験・試行・社会的交渉を通じた主動的な認識過程と見なす。', '1980年代から1990年代に行動主義を置き換える学習理論の主流となり、子ども中心教育・探究学習・プロジェクト学習・スキャフォルディングの理論的根拠となった。現在も多くの教科書・教員養成課程で参照される。', 'learning_science', 'Constructivism', 1920, NULL, '行動主義的学習観,受動的知識受信論', '学習の構成,既有知識,スキーマ,社会的相互作用,能動的学習,子ども中心教育', 'constructivism,schema,prior knowledge,active learning,sociocultural learning', '["Jean Piaget","Lev Vygotsky","Jerome Bruner"]', '[{"title":"Constructivism in Education: Exploring the Contributions of Piaget, Vygotsky, and Bruner","year":1980,"verified":false,"source_id":"jpms_src_010100"}]', 88, 'pending_verification', 'primary', 70),
